css:
.loader {color: var(--loader-color, #16a34a);
  --loader-secondary-color: #86efac;
  --loader-bg: #ffffff;
   width: 65px;
   height: 30px;
   position: relative;
}
.loader:before  {
  content: "";
   position: absolute;
   border-radius: 50px;
   box-shadow: 0 0 0 3px inset currentColor;
   animation: l3 0.75s infinite alternate;
}
@keyframes l3  {
  0%  {
  inset: 0 35px 0 0;
}
50%  {
  inset: 0 0 0 0;
}
100%  {
  inset: 0 0 0 35px;
}
}
